import React from "react";
import { useQuery } from "react-query";
import { aiAPI } from "../utils/api";
import { RadarChart, Radar, PolarGrid, PolarAngleAxis, ResponsiveContainer, Tooltip } from "recharts";
import { SparklesIcon } from "@heroicons/react/24/outline";
const radarData = [{subject:"Retention",A:72},{subject:"Engagement",A:85},{subject:"Productivity",A:78},{subject:"Hiring Speed",A:65},{subject:"Training",A:88},{subject:"Diversity",A:70}];
export default function Analytics() {
  const { data, isLoading, refetch } = useQuery("workforceInsights", () => aiAPI.workforceInsights().then(r => r.data.data), { enabled: false });
  return (
    <div className="space-y-5 animate-in">
      <div className="flex items-center justify-between"><div><h1 className="page-title">HR Analytics</h1><p className="text-slate-500 text-sm mt-0.5">Data-driven workforce intelligence</p></div><button onClick={() => refetch()} disabled={isLoading} className="btn-primary"><SparklesIcon className="w-4 h-4" />{isLoading ? "Analyzing…" : "AI Workforce Insights"}</button></div>
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
        <div className="card">
          <h2 className="section-title mb-4">HR Health Radar</h2>
          <ResponsiveContainer width="100%" height={280}><RadarChart data={radarData}><PolarGrid stroke="#e2e8f0" /><PolarAngleAxis dataKey="subject" tick={{ fontSize: 12, fill: "#64748b" }} /><Radar name="Score" dataKey="A" stroke="#6366f1" fill="#6366f1" fillOpacity={0.2} strokeWidth={2} /><Tooltip contentStyle={{ borderRadius: 8 }} /></RadarChart></ResponsiveContainer>
        </div>
        <div className="card">
          <h2 className="section-title mb-4">AI Workforce Insights</h2>
          {isLoading ? <div className="flex items-center justify-center py-8"><div className="w-8 h-8 border-4 border-slate-200 border-t-primary-500 rounded-full animate-spin" /></div> :
           data ? <div className="space-y-3">{data.insights?.map((insight, i) => (<div key={i} className={`rounded-xl p-3 border ${insight.priority==="high"?"bg-red-50 border-red-100":insight.priority==="medium"?"bg-amber-50 border-amber-100":"bg-emerald-50 border-emerald-100"}`}><div className="flex items-start justify-between gap-2"><p className="font-semibold text-sm text-slate-800">{insight.title}</p><span className={`badge text-xs flex-shrink-0 ${insight.priority==="high"?"badge-danger":insight.priority==="medium"?"badge-warning":"badge-success"}`}>{insight.priority}</span></div><p className="text-xs text-slate-600 mt-1">{insight.description}</p>{insight.action&&<p className="text-xs font-medium text-primary-600 mt-2">→ {insight.action}</p>}</div>))}</div> :
           <div className="flex flex-col items-center justify-center h-48 text-center"><SparklesIcon className="w-10 h-10 text-slate-300 mb-3" /><p className="text-slate-500 text-sm">Click AI Workforce Insights to generate analysis</p></div>}
        </div>
      </div>
    </div>
  );
}
